kernel_src = """
#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k03241Custom {
public:
    __aicore__ inline KernelCa6k03241Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalRows, uint32_t totalCols)
    {
        totalRows_ = totalRows;
        totalCols_ = totalCols;
        xGm_.SetGlobalBuffer((__gm__ float*)x, totalRows * totalCols);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalCols);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, totalCols_ * sizeof(float));
        pipe_.InitBuffer(maxQueue_, 1, totalCols_ * sizeof(float));
        pipe_.InitBuffer(sumQueue_, 1, totalCols_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalRows_ == 0 || totalCols_ == 0) return;

        AscendC::LocalTensor<float> maxLocal = maxQueue_.AllocTensor<float>();
        AscendC::LocalTensor<float> sumLocal = sumQueue_.AllocTensor<float>();
        AscendC::SetValue(maxLocal, totalCols_, -1e30f);
        AscendC::SetValue(sumLocal, totalCols_, 0.0f);

        for (uint32_t i = 0; i < totalRows_; i++) {
            AscendC::LocalTensor<float> xRow = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xRow, xGm_[i * totalCols_], totalCols_);

            // Online update of per-column max and sum
            for (uint32_t j = 0; j < totalCols_; j++) {
                float val = xRow(j);
                float curMax = maxLocal(j);
                float curSum = sumLocal(j);
                if (val > curMax) {
                    float scale = expf(curMax - val);
                    sumLocal(j) = curSum * scale + 1.0f;
                    maxLocal(j) = val;
                } else {
                    sumLocal(j) = curSum + expf(val - curMax);
                }
            }

            inQueueX_.FreeTensor(xRow);
        }

        // Final output: log(sum) + max
        for (uint32_t j = 0; j < totalCols_; j++) {
            yGm_(j) = logf(sumLocal(j)) + maxLocal(j);
        }

        maxQueue_.FreeTensor(maxLocal);
        sumQueue_.FreeTensor(sumLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> maxQueue_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> sumQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalRows_ {0};
    uint32_t totalCols_ {0};
};

extern "C" __global__ __aicore__ void ca6k_03241_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k03241Custom op;
    op.Init(x, y, tiling_data.totalRows, tiling_data.totalCols);
    op.Process();
}
